changeSet.sql:
CREATE TABLE IF NOT EXISTS `calendar_notification_method` ( `id` BIGINT NOT NULL AUTO_INCREMENT, `code` VARCHAR(50) NOT NULL COMMENT '通知方式编码', `name` VARCHAR(100) NOT NULL COMMENT '通知方式名称', `icon` VARCHAR(50) DEFAULT NULL COMMENT '图标', `description` VARCHAR(500) DEFAULT NULL COMMENT '描述', `impl_status` TINYINT DEFAULT 0 COMMENT '实现状态: 0-未实现 1-已实现', `sort_order` INT DEFAULT 0 COMMENT '排序', `status` TINYINT DEFAULT 1 COMMENT '状态: 1-启用 0-禁用', `create_time` DATETIME DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间', `update_time` DATETIME DEFAULT CURRENT_TIMESTAMP COMMENT '更新时间', PRIMARY KEY (`id`), UNIQUE KEY `uk_cal_notification_method_code` (`code`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='通知方式配置表';
INSERT INTO `calendar_notification_method` (`code`, `name`, `icon`, `description`, `impl_status`, `sort_order`, `status`) SELECT 'app', '应用内通知', 'Bell', '在应用页面顶部显示通知', 1, 1, 1 FROM DUAL WHERE NOT EXISTS (SELECT 1 FROM `calendar_notification_method` WHERE `code` = 'app');
INSERT INTO `calendar_notification_method` (`code`, `name`, `icon`, `description`, `impl_status`, `sort_order`, `status`) SELECT 'wechat', '微信公众号', 'ChatDotRound', '通过微信公众号推送通知', 0, 2, 1 FROM DUAL WHERE NOT EXISTS (SELECT 1 FROM `calendar_notification_method` WHERE `code` = 'wechat');
INSERT INTO `calendar_notification_method` (`code`, `name`, `icon`, `description`, `impl_status`, `sort_order`, `status`) SELECT 'dingtalk', '钉钉', 'ChatLineSquare', '通过钉钉机器人推送通知', 0, 3, 1 FROM DUAL WHERE NOT EXISTS (SELECT 1 FROM `calendar_notification_method` WHERE `code` = 'dingtalk');
INSERT INTO `calendar_notification_method` (`code`, `name`, `icon`, `description`, `impl_status`, `sort_order`, `status`) SELECT 'sms', '短信', 'Iphone', '通过短信发送通知', 0, 4, 1 FROM DUAL WHERE NOT EXISTS (SELECT 1 FROM `calendar_notification_method` WHERE `code` = 'sms');

SET @calendar_event_add_mood = (
    SELECT IF(
        EXISTS (
            SELECT 1
            FROM information_schema.COLUMNS
            WHERE TABLE_SCHEMA = DATABASE()
              AND TABLE_NAME = 'calendar_event'
              AND COLUMN_NAME = 'mood'
        ),
        'SELECT 1',
        'ALTER TABLE `calendar_event` ADD COLUMN `mood` VARCHAR(50) DEFAULT NULL COMMENT ''心情(emoji或文字)'' AFTER `priority`'
    )
);
PREPARE stmt FROM @calendar_event_add_mood;
EXECUTE stmt;
DEALLOCATE PREPARE stmt;

SET @calendar_reminder_add_title = (
    SELECT IF(
        EXISTS (
            SELECT 1
            FROM information_schema.COLUMNS
            WHERE TABLE_SCHEMA = DATABASE()
              AND TABLE_NAME = 'calendar_reminder'
              AND COLUMN_NAME = 'title'
        ),
        'SELECT 1',
        'ALTER TABLE `calendar_reminder` ADD COLUMN `title` VARCHAR(20) DEFAULT NULL COMMENT ''提醒标题(不超过20字)'' AFTER `event_id`'
    )
);
PREPARE stmt FROM @calendar_reminder_add_title;
EXECUTE stmt;
DEALLOCATE PREPARE stmt;
